<style>
.sync-settings-container {
  margin-top: 0.5em;
}

.sync-description {
  color: var(--text-muted);
  font-size: 0.9em;
  margin: 0 0 1em 0;
  line-height: 1.5;
}

/* Status Display */
.sync-status-connected,
.sync-status-disconnected {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 12px 16px;
  background: var(--background-secondary);
  border-radius: 8px;
  margin-bottom: 16px;
}

.status-indicator {
  width: 10px;
  height: 10px;
  border-radius: 50%;
  flex-shrink: 0;
}

.status-indicator.connected {
  background: var(--text-success);
  box-shadow: 0 0 6px var(--text-success);
}

.status-indicator.disconnected {
  background: var(--text-muted);
}

.status-info {
  flex: 1;
}

.status-title {
  font-size: 14px;
  font-weight: 500;
  color: var(--text-normal);
}

.status-detail {
  font-size: 12px;
  color: var(--text-muted);
  margin-top: 2px;
}

.connect-button,
.disconnect-button {
  flex-shrink: 0;
}

/* Error Display */
.sync-error {
  padding: 8px 12px;
  background: var(--background-modifier-error);
  color: var(--text-error);
  border-radius: 6px;
  font-size: 13px;
  margin-bottom: 16px;
}

/* App Download */
.sync-app-download {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 12px 16px;
  background: var(--background-secondary);
  border-radius: 8px;
  margin-bottom: 16px;
}

.download-label {
  font-size: 13px;
  color: var(--text-muted);
  flex: 1;
}

.store-badges {
  display: flex;
  gap: 8px;
  flex-shrink: 0;
}

.store-badge {
  display: inline-flex;
  flex-shrink: 0;
  text-decoration: none;
  transition: opacity 0.15s ease;
}

.store-badge:hover {
  opacity: 0.85;
  text-decoration: none;
}

.store-badge-svg {
  height: 30px;
  width: auto;
}

/* Info Callout */
.sync-info-callout {
  padding: 12px;
  background: var(--background-secondary);
  border-radius: 8px;
  margin-top: 20px;
  font-size: 13px;
  color: var(--text-muted);
}

.sync-info-callout strong {
  color: var(--text-normal);
  display: block;
  margin-bottom: 8px;
}

.sync-info-callout ul {
  margin: 0;
  padding-left: 20px;
}

.sync-info-callout li {
  margin: 4px 0;
}
</style>
